  v_name VARCHAR(64);
  v_idx INTEGER := 1;
BEGIN
  IF NOT public.is_admin() THEN
    RAISE EXCEPTION 'Only global admins can reorder subcategories';
  END IF;
  FOREACH v_name IN ARRAY p_ordered_names LOOP
    UPDATE public.sub_categories
    SET sort_order = v_idx
    WHERE name = v_name;
    v_idx := v_idx + 1;
  END LOOP;
  RETURN TRUE;
END;
