  p_id UUID
)
RETURNS BOOLEAN AS $$
BEGIN
  IF NOT is_admin() THEN
    RAISE EXCEPTION 'Only admin can delete notifications';
  END IF;
  DELETE FROM public.notifications WHERE id = p_id;
  RETURN TRUE;
END;
$$ LANGUAGE plpgsql
